class Solution:
    def isAdditiveNumber(self, num):
        L = len(num)
        def valid(piece):
            return piece == '0' or not piece.startswith('0')
        for i in range(1, L):
            for j in range(i + 1, L):
                first = num[:i]
                second = num[i:j]
                if not valid(first) or not valid(second):
                    continue
                a, b = int(first), int(second)
                rest = num[j:]
                terms = 2
                ok = True
                while rest:
                    nxt = str(a + b)
                    if not rest.startswith(nxt):
                        ok = False
                        break
                    rest = rest[len(nxt):]
                    a, b = b, a + b
                    terms += 1
                if ok and terms >= 3:
                    return True
        return False

