class Solution:
    def isAdditiveNumber(self, num):
        n = len(num)
        def check(a, b, start):
            if start == n:
                return True
            s = str(a + b)
            if not num.startswith(s, start):
                return False
            return check(b, a + b, start + len(s))
        for i in range(1, n):
            if i > 1 and num[0] == '0':
                break
            for j in range(i + 1, n):
                if j - i > 1 and num[i] == '0':
                    break
                a = int(num[:i])
                b = int(num[i:j])
                if check(a, b, j):
                    return True
        return False

