var isAdditiveNumber = function(num) {
    const n = num.length;
    const check = (a, b, start) => {
        if (start === n) return true;
        const s = (a + b).toString();
        if (!num.startsWith(s, start)) return false;
        return check(b, a + b, start + s.length);
    };
    for (let i = 1; i < n; i++) {
        if (i > 1 && num[0] === '0') break;
        for (let j = i + 1; j < n; j++) {
            if (j - i > 1 && num[i] === '0') break;
            const a = BigInt(num.slice(0, i));
            const b = BigInt(num.slice(i, j));
            if (check(a, b, j)) return true;
        }
    }
    return false;
};
